// Get the contacts object from the input
const contacts = $json.contacts;

// Convert the object into an array of its entries [key, value]
const mappedContacts = Object.entries(contacts).map(([id, details]) => {
  return {
    ...details,          // Keep all existing fields (error, data, etc.)
    original_id: id      // Add the key as original_id
  };
});

// Return the result as a new list of items
return {json: {mappedContacts}};
